require 'active_record'
require 'active_support/core_ext'
require 'lru_redux'
require 'ruby-openhash'
require 'hashie'

class CRUDHash < Hash
  def create(key, value)
    self[key] = value
  end

  def read(key)
    self[key]
  end

  def update(key, value)
    self[key] = value
  end

  def delete(key)
    self.delete(key)
  end
end

class Dictionary < CRUDHash
end

class LRUHash < CRUDHash
  def initialize(options = {})
    @lru = LRU::Hash.new(options)
    super
  end

  def read(key)
    @lru.read(key) || super
  end

  def update(key, value)
    @lru.write(key, value)
    super
  end

  def delete(key)
    @lru.delete(key)
    super
  end
end

class OpenHash < CRUDHash
  def initialize(size = 128)
    @hash = OpenStruct.new(size: size)
  end

  def create(key, value)
    index = key.hash % size
    @hash.send(:[], index).merge(key => value)
  end

  def read(key)
    index = key.hash % size
    @hash.send(:[], index)[key]
  end

  def update(key, value)
    index = key.hash % size
    @hash.send(:[], index)[key] = value
  end

  def delete(key)
    index = key.hash % size
    @hash.send(:[], index).delete(key)
  end
end

class KeyHash < CRUDHash
  def initialize(&block)
    @block = block
  end

  def create(key, value)
    @block.call(key, value)
    super
  end
end
