class EventEmitter
  def initialize
    @events = {}
  end

  def on(event, &block)
    return unless block_given?
    (@events[event] ||= Set.new).add(block)
  end

  def off(event, &block)
    return unless block_given? || event.is_a?(Proc)
    if event.is_a?(Proc)
      (@events[event] ||= Set.new).delete(event)
    else
      (@events[event] ||= Set.new).delete(block)
    end
  end

  def emit(event, *args)
    return unless @events.key?(event)
    (@events[event].to_a).each { |block| block.call(*args) }
  end
end

