# observer.rb
class Observable
  def initialize
    @observers = []
  end

  def add_observer(observer)
    @observers << observer
  end

  def remove_observer(observer)
    @observers.delete(observer)
  end

  def notify_observers(method_name, *args)
    @observers.each do |observer|
      observer.send(method_name, *args)
    end
  end
end

# example usage
class WeatherStation < Forwardable
  extend Forwardable
  def_delegators :@weather, :temperature, :humidity

  def initialize
    @weather = Weather.new
    @observers = []
  end

  def add_observer(observer)
    @observers << observer
  end

  def remove_observer(observer)
    @observers.delete(observer)
  end

  def notify_observers(method_name, *args)
    @observers.each do |observer|
      observer.send(method_name, *args)
    end
  end

  def set_measurements(temp, humidity)
    @weather.temperature = temp
    @weather.humidity = humidity
    notify_observers(:update, temp, humidity)
  end
end

class Weather
  attr_accessor :temperature, :humidity
end

class Display
  def initialize
    @name = "Display"
  end

  def update(temp, humidity)
    puts "#{@name} updating with temp: #{temp}, humidity: #{humidity}"
  end
end

station = WeatherStation.new
station.add_observer(Display.new)
station.set_measurements(25, 60)
```

In this example, we define an `Observable` class that maintains a list of observers and provides methods to add, remove and notify observers. We also define a `WeatherStation` class that uses `Observable` to notify observers of temperature and humidity changes. The `Display` class is an example observer that updates its display when notified.
